import React from "react";

function Profile() {

  const user =
  JSON.parse(
    localStorage.getItem("user")
  );

  return (

    <div className="container mt-5">

      <div className="card shadow p-4">

        <h2>
          My Profile
        </h2>

        <hr />

        <p>
          <strong>Name:</strong>{" "}
          {user?.name}
        </p>

        <p>
          <strong>Email:</strong>{" "}
          {user?.email}
        </p>

        <p>
          <strong>Role:</strong>{" "}
          {user?.role}
        </p>

      </div>

    </div>

  );

}

export default Profile;
